import React, { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import Navbar from '../../components/common/Navbar';
import GlassCard from '../../components/common/GlassCard';
import { User, Calendar, CreditCard, Star } from 'lucide-react';

const ParentDashboard = () => {
    const { user } = useAuth();
    const [activeTab, setActiveTab] = useState('bookings');

    const bookings = [
        { id: 1, sitter_name: 'María López', date: '2026-05-15', hours: 4, total_amount: 55.00, status: 'completed' },
        { id: 2, sitter_name: 'Ana García', date: '2026-05-20', hours: 3, total_amount: 40.00, status: 'pending' },
        { id: 3, sitter_name: 'Sofía Martínez', date: '2026-05-25', hours: 5, total_amount: 70.00, status: 'awaiting_payment' },
    ];

    const getStatusColor = (status) => {
        switch(status) {
            case 'completed': return 'bg-green-100 text-green-700';
            case 'pending': return 'bg-yellow-100 text-yellow-700';
            case 'awaiting_payment': return 'bg-primary-fixed-dim text-primary';
            default: return 'bg-gray-100 text-gray-700';
        }
    };

    const getStatusLabel = (status) => {
        switch(status) {
            case 'completed': return 'Completado';
            case 'pending': return 'Pendiente';
            case 'awaiting_payment': return 'Pago Pendiente';
            default: return status;
        }
    };

    return (
        <div className="min-h-screen bg-background text-on-surface">
            <Navbar />
            <div className="container mx-auto px-4 pt-28 pb-12 flex flex-col md:flex-row gap-8">
                {/* Sidebar */}
                <aside className="w-full md:w-64 flex-shrink-0">
                    <GlassCard className="rounded-[32px] p-6 shadow-xl sticky top-28">
                        <div className="flex flex-col items-center mb-8">
                            <div className="w-24 h-24 rounded-full bg-primary-fixed-dim flex items-center justify-center text-primary text-3xl font-bold mb-4">
                                {user?.full_name?.charAt(0) || 'P'}
                            </div>
                            <h2 className="font-display-lg text-xl font-bold text-center">{user?.full_name}</h2>
                            <p className="text-on-surface-variant text-sm text-center">Padre</p>
                        </div>

                        <nav className="flex flex-col gap-2">
                            <button 
                                onClick={() => setActiveTab('bookings')}
                                className={`flex items-center gap-3 p-3 rounded-xl transition-all font-bold ${activeTab === 'bookings' ? 'bg-primary text-white shadow-md' : 'hover:bg-surface-container'}`}
                            >
                                <Calendar size={20} /> Mis Contrataciones
                            </button>
                            <button 
                                onClick={() => setActiveTab('profile')}
                                className={`flex items-center gap-3 p-3 rounded-xl transition-all font-bold ${activeTab === 'profile' ? 'bg-primary text-white shadow-md' : 'hover:bg-surface-container'}`}
                            >
                                <User size={20} /> Mi Perfil
                            </button>
                        </nav>
                    </GlassCard>
                </aside>

                {/* Main Content */}
                <main className="flex-1">
                    {activeTab === 'bookings' && (
                        <div>
                            <h2 className="font-display-lg text-3xl font-bold text-primary mb-6">Mis Contrataciones</h2>
                            <div className="space-y-4">
                                {bookings.map(booking => (
                                    <GlassCard key={booking.id} className="rounded-[24px] p-6 flex flex-col md:flex-row items-center justify-between gap-6 shadow-md hover:shadow-lg transition-shadow">
                                        <div className="flex-1">
                                            <h3 className="font-display-lg text-xl font-bold mb-1">{booking.sitter_name}</h3>
                                            <p className="text-on-surface-variant text-sm flex items-center gap-4">
                                                <span><Calendar className="inline mr-1" size={14}/> {booking.date}</span>
                                                <span>{booking.hours} horas</span>
                                            </p>
                                        </div>
                                        <div className="flex flex-col items-end gap-2">
                                            <span className="font-bold text-lg">${booking.total_amount.toFixed(2)}</span>
                                            <span className={`px-3 py-1 rounded-full text-xs font-bold ${getStatusColor(booking.status)}`}>
                                                {getStatusLabel(booking.status)}
                                            </span>
                                        </div>
                                        <div className="flex gap-2">
                                            {booking.status === 'awaiting_payment' && (
                                                <button className="bg-primary text-white px-4 py-2 rounded-full text-sm font-bold shadow-md hover:bg-primary-container transition">
                                                    Pagar
                                                </button>
                                            )}
                                            {booking.status === 'completed' && (
                                                <button className="bg-secondary-fixed text-on-secondary-fixed px-4 py-2 rounded-full text-sm font-bold shadow-md hover:bg-secondary-fixed-dim transition flex items-center gap-1">
                                                    <Star size={14}/> Reseñar
                                                </button>
                                            )}
                                        </div>
                                    </GlassCard>
                                ))}
                            </div>
                        </div>
                    )}

                    {activeTab === 'profile' && (
                        <div>
                            <h2 className="font-display-lg text-3xl font-bold text-primary mb-6">Mi Perfil</h2>
                            <GlassCard className="rounded-[32px] p-8 shadow-md">
                                <form className="flex flex-col gap-6">
                                    <div>
                                        <label className="block text-xs font-bold text-outline uppercase tracking-wider mb-2">Nombre Completo</label>
                                        <input type="text" className="w-full p-4 rounded-xl border-none bg-surface-container-low" defaultValue={user?.full_name} />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-outline uppercase tracking-wider mb-2">Correo</label>
                                        <input type="email" disabled className="w-full p-4 rounded-xl border-none bg-surface-container-low opacity-60" value={user?.email} />
                                    </div>
                                    <button className="bg-primary text-white px-6 py-3 rounded-full font-bold self-start mt-4">Guardar Cambios</button>
                                </form>
                            </GlassCard>
                        </div>
                    )}
                </main>
            </div>
        </div>
    );
};

export default ParentDashboard;
